# Apply the policy at Management Group level (covers all child subscriptions)
az policy assignment create \
  --name "restrict-to-eu-regions-mg" \
  --display-name "GDPR: EU geography enforcement (management group)" \
  --policy "e56962a6-4747-49cd-b67b-bf8b01975c4c" \
  --scope /providers/Microsoft.Management/managementGroups/<mg-id> \
  --params '{
    "listOfAllowedLocations": {
      "value": ["northeurope", "westeurope", "uksouth", "ukwest",
                "germanywestcentral", "germanynorth", "francecentral"]
    }
  }' \
  --enforcement-mode Default    # Default = Deny; DoNotEnforce = audit only
